setupScan.query:
#graphql
  query BackupRegionNoRegionMarketScan {
    backupRegion {
      __typename
      ... on MarketRegionCountry {
        code
      }
    }
    markets(first: 20) {
      nodes {
        id
        name
        status
        type
        conditions {
          regionsCondition {
            regions(first: 250) {
              nodes {
                ... on MarketRegionCountry {
                  code
                }
              }
            }
          }
        }
      }
    }
  }

